// Validar token JWT
const token = $input.first().json.headers['x-admin-token'];
if (!token) return [{json: {ok: 'false', error: 'No autorizado'}}];
try {
  const decoded = Buffer.from(token, 'base64').toString('utf8');
  const parts = decoded.split('|');
  if (parts.length !== 3 || parts[2] !== 'CrackTesos2026_Admin_Token') {
    return [{json: {ok: 'false', error: 'Token inválido'}}];
  }
  const tokenAge = Date.now() - parseInt(parts[1]);
  if (tokenAge > 8 * 3600 * 1000) return [{json: {ok: 'false', error: 'Sesión expirada. Vuelve a ingresar.'}}];
} catch(e) {
  return [{json: {ok: 'false', error: 'Token inválido'}}];
}

const body = $input.first().json.body;
const triviaNumber = parseInt(body.trivia_number);

if (!triviaNumber || triviaNumber < 1) return [{json: {ok: 'false', error: 'Número de trivia inválido'}}];
if (!body.records || !Array.isArray(body.records) || body.records.length === 0) {
  return [{json: {ok: 'false', error: 'No se recibieron registros del archivo'}}];
}

// Función de cálculo de multiplicador por rangos
// Regla: de 15 a 29 → x2, de 30 a 44 → x3, etc. (incrementa 1x cada 15 códigos desde 15)
function calcMultiplier(codes) {
  const n = parseInt(codes) || 0;
  if (n < 15) return 0; // no aplica
  return Math.floor((n - 15) / 15) + 2;
}

// Normalizar registros e incluir códigos
const records = body.records.map(r => {
  const codes = parseInt(r.number_of_codes || r.codigos || r.codes || 0);
  const mult = calcMultiplier(codes);
  let phone = String(r.phone || r.telefono || '').replace(/[^0-9]/g, '');
  if (phone && !phone.startsWith('57') && phone.length === 10) phone = '57' + phone;
  return {
    document_id: String(r.document_id || r.cedula || '').trim(),
    phone,
    name: String(r.name || r.nombre || '').trim(),
    number_of_codes: codes,
    multiplier: mult
  };
}).filter(r => (r.document_id || r.phone) && r.multiplier > 0);

if (records.length === 0) {
  return [{json: {ok: 'false', error: 'Ningún registro tiene 15 o más códigos para aplicar multiplicador'}}];
}

return [{json: {
  ok: 'true',
  trivia_number: triviaNumber,
  records,
  operator_email: body.operator_email || 'unknown',
  source_file: body.source_file || 'upload'
}}];

// Cruzar registros del archivo con la BD
const validated = $('Validar').first().json;
const triviaRow = $input.first().json;

if (!triviaRow.trivia_id) {
  return [{json: {ok: 'false', error: `Trivia #${validated.trivia_number} no encontrada`}}];
}

// Preparar listas para cruce SQL (cada registro tiene su propio multiplier calculado)
const docs = validated.records.map(r => r.document_id).filter(Boolean);
const phones = validated.records.map(r => r.phone).filter(Boolean);

// Mapa de multiplier por documento/teléfono para recuperar después del JOIN
const multByDoc = {};
const multByPhone = {};
validated.records.forEach(r => {
  if (r.document_id) multByDoc[r.document_id] = {multiplier: r.multiplier, codes: r.number_of_codes};
  if (r.phone) multByPhone[r.phone] = {multiplier: r.multiplier, codes: r.number_of_codes};
});

return [{json: {
  ok: 'true',
  trivia_id: triviaRow.trivia_id,
  trivia_number: validated.trivia_number,
  records: validated.records,
  mult_by_doc: multByDoc,
  mult_by_phone: multByPhone,
  docs_list: docs.map(d => `'${d}'`).join(','),
  phones_list: phones.map(p => `'${p}'`).join(','),
  operator_email: validated.operator_email,
  source_file: validated.source_file
}}];

const prepData = $('Preparar Cruce').first().json;
const rows = $input.all();
const multByDoc = prepData.mult_by_doc || {};
const multByPhone = prepData.mult_by_phone || {};

// Enriquecer cada usuario con su multiplicador individual
const eligible = rows.map(r => {
  const u = r.json;
  // Buscar multiplicador por documento (prioridad) o teléfono
  const info = multByDoc[u.document_id] || multByPhone[u.phone] || {multiplier: 0, codes: 0};
  const mult = info.multiplier;
  const codes = info.codes;
  const goalsToAdd = u.goals_trivia * (mult - 1);
  const goalsFinal = u.goals_trivia * mult;
  return {
    ...u,
    multiplier: mult,
    number_of_codes: codes,
    goals_to_add: goalsToAdd,
    goals_final: goalsFinal
  };
}).filter(u => u.multiplier > 0);

const totalGoalsToAdd = eligible.reduce((s, r) => s + r.goals_to_add, 0);
const alreadyApplied = eligible.filter(r => r.already_applied).length;

const preview_table = eligible.map(r => ({
  nombre: r.name,
  cedula: r.document_id,
  codigos: r.number_of_codes,
  multiplicador: `x${r.multiplier}`,
  goles_actuales_trivia: r.goals_trivia,
  goles_a_agregar: r.goals_to_add,
  goles_nuevos_trivia: r.goals_final,
  ya_aplicado: r.already_applied ? 'SÍ — ADVERTENCIA' : 'No'
}));

return [{json: {
  ok: 'true',
  trivia_number: prepData.trivia_number,
  trivia_id: prepData.trivia_id,
  operator_email: prepData.operator_email,
  source_file: prepData.source_file,
  summary: {
    total_en_archivo: prepData.records.length,
    total_elegibles: eligible.length,
    total_goles_a_agregar: totalGoalsToAdd,
    ya_con_multiplicador: alreadyApplied
  },
  preview_table,
  eligible_users: eligible
}}];
